queries.sparql:
PREFIX : <http://ambrosia.example.org/jobpostings#>
PREFIX p: <http://ambrosia.example.org/jobpostings/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?o0 WHERE {
  {
    ?real_estate_agents a :Real_Estate_Agents .
    ?real_estate_agents p:name ?name .
    BIND(?name AS ?o0)
  }
  UNION
  {
    ?property_managers a :Property_Managers .
    ?property_managers p:name ?name .
    ?property_managers p:commission ?commission_f .
    FILTER(STR(?commission_f) = "5%")
    BIND(?name AS ?o0)
  }
}

